import { IMessageEvent, MessageEvent } from '@nitrots/nitro-renderer/src/core'
import { TradeCloseParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/TradeCloseParser';

export class TradeCloseEvent extends MessageEvent implements IMessageEvent
{
constructor(callback: Function)
{
super(callback, TradeCloseParser);
}

public getParser(): TradeCloseParser
{
return this.parser as TradeCloseParser;
}
}